1	export interface ItemSpec {
2	  type: string;
3	}
4	
5	export interface Customer {
6	  yearsWithMHPCO: number;
7	}
8	
9	export interface QuoteInput {
10	  customer: Customer;
11	  items: ItemSpec[];
12	}
13	
14	export interface QuoteResult {
15	  premium: number;
16	}
17	
18	const PROCESSING_FEE = 5;
19	const FIRST_INSURANCE_RATE = 0.1;
20	
21	const BASE_PREMIUMS: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	  staff: 80,
25	  potion: 40,
26	};
27	
28	function basePremiumFor(item: ItemSpec): number {
29	  return BASE_PREMIUMS[item.type] ?? 0;
30	}
31	
32	export function quote(input: QuoteInput): QuoteResult {
33	  const policyBasePremium = input.items.reduce(
34	    (sum, item) => sum + basePremiumFor(item),
35	    0
36	  );
37	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_RATE;
38	  return {
39	    premium: policyBasePremium + firstInsuranceSurcharge + PROCESSING_FEE,
40	  };
41	}
42	
43	export function claim(): unknown {
44	  return undefined;
45	}
